const fs = require('fs');
const profile = JSON.parse(fs.readFileSync('/data/user_profile.json', 'utf8'));
const queue = (() => { try { return JSON.parse(fs.readFileSync('/data/podcast_queue.json','utf8')); } catch(e) { return {items:[]}; } })();
const podcasts = (profile.known_podcasts || []).filter(p => p.rss_url || p.youtube_rss_url);
return [{json: {podcasts, queue_items: queue.items}}];

const {podcasts} = $input.first().json;
if (!podcasts.length) return [{json: {url: null, name: 'empty', skip: true}}];
const sources = [];
for (const p of podcasts) {
  // Try both RSS and YouTube — deduplicated later by episode title
  if (p.rss_url) sources.push({json: {url: p.rss_url, name: p.name, podcast_id: p.id || p.name, source: 'rss'}});
  if (p.youtube_rss_url && p.youtube_rss_url !== p.rss_url) {
    sources.push({json: {url: p.youtube_rss_url, name: p.name, podcast_id: p.id || p.name, source: 'youtube'}});
  }
  // Fallback: if neither, skip
}
if (!sources.length) return [{json: {url: null, name: 'empty', skip: true}}];
return sources;

const fs = require('fs');
const items = $input.all().filter(i => !i.json.error);
const cutoff = new Date(Date.now() - 36 * 60 * 60 * 1000); // 36h window — covers early morning uploads

// Load skip_clips settings
const skipClipsMap = {};
try {
  const profile = JSON.parse(fs.readFileSync('/data/user_profile.json', 'utf8'));
  for (const p of (profile.known_podcasts || [])) { if (p.skip_clips) skipClipsMap[p.name.toLowerCase()] = true; }
} catch(e) {}
const CLIP_RE = /\b(short|shorts|clip|clips|recorte|recortes|highlight|highlights|teaser|trailer|avance|snippet|adelanto|cortito|mini)\b|#shorts/i;
function isClip(podcastName, title, duration) {
  if (!skipClipsMap[podcastName.toLowerCase()]) return false;
  if (duration) {
    const parts = String(duration).split(':').map(Number);
    const secs = parts.length === 3 ? parts[0]*3600+parts[1]*60+parts[2] : parts.length === 2 ? parts[0]*60+parts[1] : parseInt(duration,10);
    if (secs > 0 && secs < 600) return true;
  }
  return CLIP_RE.test(title);
}

const newEpisodes = [];
const seenTitles = new Set(); // dedup: same episode from RSS + YouTube RSS
for (const item of items) {
  const feed = item.json;
  const episodes = Array.isArray(feed) ? feed : [feed];
  for (const ep of episodes) {
    // Support pubDate (RSS 2.0), isoDate (parsed), published (Atom/YouTube)
    const pubDate = ep.pubDate || ep.isoDate || ep.date || ep.published;
    if (!pubDate) continue;
    const d = new Date(pubDate);
    if (isNaN(d.getTime())) continue;
    if (d >= cutoff && d <= new Date()) {
      // n8n rssFeedRead puts feed-level title in ep.feed.title
      const podName = ep.feed?.title || ep.meta?.title || ep.feed_title || 'Podcast';
      const title = ep.title || 'Episodio sin título';
      // Deduplicate by normalized title (same ep from RSS + YouTube feed)
      const titleKey = title.toLowerCase().replace(/[^a-z0-9áéíóúñ]/g, '').slice(0, 60);
      if (seenTitles.has(titleKey)) continue;
      seenTitles.add(titleKey);
      const dur = ep.itunes?.duration || ep.duration || null;
      if (isClip(podName, title, dur)) continue;
      newEpisodes.push({
        podcast_name: podName,
        title,
        url: ep.link || ep.enclosure?.url || '',
        spotify_url: null,
        pub_date: pubDate,
        duration: dur,
        description: (ep.content || ep.summary || ep.contentSnippet || '').slice(0, 200)
      });
    }
  }
}
if (!newEpisodes.length) return [{json: {skip: true, episodes: [], feed_count: items.length}}];
return [{json: {skip: false, episodes: newEpisodes, feed_count: items.length}}];

const fs = require('fs');
const {episodes} = $input.first().json;
let spotifyToken = null;
try {
  const tokenData = JSON.parse(fs.readFileSync('/data/spotify_token.json', 'utf8'));
  spotifyToken = tokenData.access_token;
} catch(e) {}
return episodes.map(ep => ({json: {...ep, spotify_token: spotifyToken}}));

const fs = require('fs');
const items = $input.all();
if (!items.length) return [];

const cachePath = '/data/v4_episodes_cache.json';
let cache = {};
try { cache = JSON.parse(fs.readFileSync(cachePath, 'utf8')); } catch(e) {}

const result = [];
let counter = 0;
const now = Date.now();
for (const item of items) {
  const ep = item.json;
  const episode_id = 'v4' + now.toString(36).slice(-6) + (counter++).toString(36);

  // Platform badge: YouTube source gets 📺, Spotify gets 🎵, RSS gets 🎙️
  const hasYoutube = ep.url && (ep.url.includes('youtube.com') || ep.url.includes('youtu.be'));
  const hasSpotify = !!ep.spotify_url;
  const platformBadge = hasYoutube ? '📺' : hasSpotify ? '🎵' : '🎙️';

  // Save to cache for V2 queue handler lookup
  cache[episode_id] = {
    title: ep.title || 'Episodio',
    podcast: ep.podcast_name || 'Podcast',
    url: ep.spotify_url || ep.url || '',
    youtube_url: hasYoutube ? ep.url : null,
    spotify_url: ep.spotify_url || null,
    duration_min: null
  };

  const dur = ep.duration ? ` · ⏱️ ${ep.duration}` : '';
  let text = `${platformBadge} *${(ep.podcast_name || 'Podcast').slice(0, 40)}*\n_${(ep.title || 'Episodio').slice(0, 80)}${dur}_`;
  if (ep.description) text += `\n${ep.description.slice(0, 120)}`;

  // Show platform links
  const links = [];
  if (hasYoutube) links.push(`[📺 YouTube](${ep.url})`);
  if (hasSpotify) links.push(`[🎵 Spotify](${ep.spotify_url})`);
  if (!hasYoutube && !hasSpotify && ep.url) links.push(`[🔗 Escuchar](${ep.url})`);
  if (links.length) text += `\n${links.join('   ')}`;

  const reply_markup = {
    inline_keyboard: [[
      {text: '📋 Añadir a lista', callback_data: `q_add:${episode_id}`},
      {text: '✅ Ya lo escuché', callback_data: `q_listened:${episode_id}`}
    ]]
  };

  result.push({json: {text, episode_id, reply_markup}});
}

fs.writeFileSync(cachePath, JSON.stringify(cache, null, 2));
return result;
